const booking = $('Get Booking To Reassign').first().json;
const fields = booking.fields || {};

const bookingBeds = fields['Booking Beds'] || [];

if (!bookingBeds.length) {
  return [{
    json: {
      booking_record_id: booking.id,
      booking_id: fields['Booking ID'] || '',
      no_booking_beds_found: true
    }
  }];
}

return bookingBeds.map(id => ({
  json: {
    booking_record_id: booking.id,
    booking_id: fields['Booking ID'] || '',
    booking_bed_record_id: id
  }
}));

const booking = $('Get Booking To Reassign').first().json || {};
const fields = booking.fields || {};

function toNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : 0;
}

const guestCountFromBooking = toNumber(fields['Guest Count']);

const bookingBeds = Array.isArray(fields['Booking Beds'])
  ? fields['Booking Beds']
  : [];

const guestCountFromExistingBeds = bookingBeds.length;

const guestCountFromWebhook = toNumber(
  $json.body?.guest_count ||
  $json.guest_count
);

const effectiveGuestCount =
  guestCountFromBooking > 0
    ? guestCountFromBooking
    : guestCountFromExistingBeds > 0
      ? guestCountFromExistingBeds
      : guestCountFromWebhook > 0
        ? guestCountFromWebhook
        : 0;

const checkIn = fields['Check In'] || null;
const checkOut = fields['Check Out'] || null;

const canReassign =
  !!booking.id &&
  !!checkIn &&
  !!checkOut &&
  effectiveGuestCount > 0;

return [
  {
    json: {
      booking_record_id: booking.id,
      booking_id: fields['Booking ID'] || $json.body?.booking_id || null,

      check_in: checkIn,
      check_out: checkOut,

      guest_count: effectiveGuestCount,
      original_guest_count: guestCountFromBooking,
      existing_booking_bed_count: guestCountFromExistingBeds,

      room_preference:
        $json.body?.room_preference ||
        fields['Room Preference'] ||
        'shared',

      guest_gender_group_type:
        $json.body?.guest_gender_group_type ||
        fields['Guest Gender / Group Type'] ||
        'unknown',

      requested_room_type:
        fields['Requested Room Type'] ||
        'shared',

      status: fields['Status'] || null,
      payment_status: fields['Payment Status'] || null,

      booking_beds: bookingBeds,
      can_reassign: canReassign,

      error: canReassign
        ? null
        : 'Cannot reassign because booking id, check-in, check-out, or guest count is missing.'
    }
  }
];
